            createdAt = now,
            updatedAt = now,
            lastEditedAt = now
        )
    )
    addFlashcardsFromQuestionsToDeck(deckId, questions.map { it.id }, config)
    if (clearMarksAfter) {
        questions.filter { it.isMarked }.forEach { question ->
            questionDao.updateQuestion(question.copy(isMarked = false, updatedAt = now, lastEditedAt = now))
        }
    }
    return deckId
}

